const event = $('Execute Workflow Trigger').item.json || {};
const rules = $json.snapshot || {};

return [{
  json: {
    correlation_id: event.correlation_id || `cg-${Date.now()}`,
    event_type: event.event_type || 'debate',
    actor: event.actor || 'system',
    payload: typeof event.payload === 'string' ? event.payload : JSON.stringify(event.payload || {}),
    project_rules: JSON.stringify(rules, null, 2)
  }
}];

let raw = $json.text || $json.output || $json.response || '';
raw = String(raw).replace(/```json/gi, '').replace(/```/g, '').trim();
const firstBrace = raw.indexOf('{');
const lastBrace = raw.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) raw = raw.slice(firstBrace, lastBrace + 1);

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (err) {
  parsed = {
    evaluation: raw,
    risk_level: 'medium',
    guidance: 'Model response could not be parsed cleanly.',
    requires_human_approval: true,
    parse_error: err.message
  };
}

const ctx = $('Prepare Guardian Context').item.json;
const risk = ['low', 'medium', 'high'].includes(String(parsed.risk_level || '').toLowerCase())
  ? String(parsed.risk_level).toLowerCase()
  : 'medium';

return [{
  json: {
    correlation_id: ctx.correlation_id,
    agent_role: 'Context Guardian',
    decision_type: 'context_guardian',
    input_summary: `Context review for ${ctx.event_type} by ${ctx.actor}`,
    context_used: {
      event_type: ctx.event_type,
      actor: ctx.actor,
      payload: ctx.payload,
      project_rules: ctx.project_rules
    },
    evidence: {
      model_output: parsed,
      parse_error: parsed.parse_error || null
    },
    decision: {
      evaluation: parsed.evaluation || 'Sin evaluación generada',
      guidance: parsed.guidance || 'Revisar manualmente.'
    },
    recommendation: parsed.guidance || parsed.evaluation || 'Revisar manualmente la coherencia del cambio.',
    confidence: parsed.confidence || 0.78,
    risk_level: risk,
    requires_human_approval: Boolean(parsed.requires_human_approval || risk === 'high')
  }
}];
